// List all ACTIVE Stripe subscriptions, count by plan, calculate MRR.
const helpers = this.helpers;
const auth = 'Bearer ' + $env.STRIPE_SECRET_KEY;
let subs = [];
let startingAfter = null;
let more = true;
while (more) {
  const url = 'https://api.stripe.com/v1/subscriptions?status=active&limit=100&expand[]=data.items.data.price' + (startingAfter ? ('&starting_after=' + startingAfter) : '');
  const page = await helpers.httpRequest({ method: 'GET', url: url, headers: { Authorization: auth }, json: true });
  const data = page.data || [];
  subs = subs.concat(data);
  if (page.has_more && data.length) { startingAfter = data[data.length - 1].id; } else { more = false; }
}

function intervalLabel(price) {
  if (!price || !price.recurring) return 'other';
  const i = price.recurring.interval, c = price.recurring.interval_count || 1;
  if (i === 'week' && c === 1) return 'weekly';
  if (i === 'week' && c === 2) return 'fortnightly';
  if (i === 'month' && c === 1) return 'monthly';
  if (i === 'month' && c === 3) return 'quarterly';
  return 'other';
}
function monthlyEquiv(price) {
  if (!price || !price.recurring) return 0;
  const amt = (price.unit_amount || 0) / 100;
  const i = price.recurring.interval, c = price.recurring.interval_count || 1;
  const periodsPerYear = (i === 'week' ? 52 : i === 'month' ? 12 : i === 'year' ? 1 : 12) / c;
  return (amt * periodsPerYear) / 12;
}

const counts = { weekly: 0, fortnightly: 0, monthly: 0, quarterly: 0, other: 0 };
let mrr = 0;
for (const s of subs) {
  const items = (s.items && s.items.data) || [];
  for (const it of items) {
    const price = it.price || it.plan;
    counts[intervalLabel(price)] += 1;
    mrr += monthlyEquiv(price) * (it.quantity || 1);
  }
}

return [{ json: {
  subscriber_count: subs.length,
  counts: counts,
  mrr: Math.round(mrr * 100) / 100,
  flags: [],
  generated_at: new Date().toISOString()
} }];

// Owner SMS summary (ClickSend dedicated number).
const helpers = this.helpers;
const d = $json;
const c = d.counts;
const text = 'Prisoncall monthly: ' + d.subscriber_count + ' active subs (W' + c.weekly + '/F' + c.fortnightly + '/M' + c.monthly + '/Q' + c.quarterly + '). MRR $' + d.mrr + '. Flags: ' + ((d.flags && d.flags.length) ? d.flags.join('; ') : 'none') + '.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] }, json: true });
return [{ json: { ...d, owner_sms: resp } }];

